import{_ as e,o as a,c as n,ag as s}from"./chunks/framework.CNG7EpJN.js";const P=JSON.parse('{"title":"OP / runner 連携運用","description":"","frontmatter":{"title":"OP / runner 連携運用","chapter":14,"plan":["all"],"role":["posla-admin"],"audience":"POSLA 運営チーム / AI運用担当","keywords":["op","runner","codex","alert","incident","google-chat","monitor-event"],"last_updated":"2026-04-27T00:00:00.000Z","maintainer":"POSLA運営"},"headers":[],"relativePath":"internal/13-op-runner-integration.md","filePath":"internal/13-op-runner-integration.md"}'),d={name:"internal/13-op-runner-integration.md"};function l(i,t,o,r,p,c){return a(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="_14-op-runner-連携運用" tabindex="-1">14. OP / runner 連携運用 <a class="header-anchor" href="#_14-op-runner-連携運用" aria-label="Permalink to &quot;14. OP / runner 連携運用&quot;">​</a></h1><p>この章は、POSLA本体、AI運用支援基盤 <code>op.posla.jp</code>、調査実行基盤 <code>runner.posla.jp</code> の接続と日常運用をまとめた社内向け手順です。</p><div class="warning custom-block"><p class="custom-block-title">この章の前提</p><ul><li>POSLA本体は顧客が使う業務システム</li><li>OPはPOSLAを監視・調査する内部運用画面</li><li>runnerはOPから呼ばれる読み取り専用の調査コンテナ</li><li>Phase 1ではOP / runnerからdeploy、migration、DB writeを実行しない</li></ul></div><h2 id="_14-1-全体像" tabindex="-1">14.1 全体像 <a class="header-anchor" href="#_14-1-全体像" aria-label="Permalink to &quot;14.1 全体像&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POSLA control / cell</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  | alert / 障害報告</span></span>
<span class="line"><span>  v</span></span>
<span class="line"><span>op.posla.jp</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  | investigation request</span></span>
<span class="line"><span>  v</span></span>
<span class="line"><span>runner.posla.jp</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  | read-only</span></span>
<span class="line"><span>  +-- GitHub / POSLA code</span></span>
<span class="line"><span>  +-- POSLA DB SELECT</span></span>
<span class="line"><span>  +-- log files</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  v</span></span>
<span class="line"><span>Codex CLI report</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  v</span></span>
<span class="line"><span>Google Chat: 小田さんが今やること / 理由</span></span></code></pre></div><h2 id="_14-2-役割分担" tabindex="-1">14.2 役割分担 <a class="header-anchor" href="#_14-2-役割分担" aria-label="Permalink to &quot;14.2 役割分担&quot;">​</a></h2><table tabindex="0"><thead><tr><th>役割</th><th>担当</th><th>実行してよいこと</th><th>実行しないこと</th></tr></thead><tbody><tr><td>POSLA</td><td>業務アプリ / cell</td><td>ping、snapshot、monitor_event作成、障害報告送信</td><td>OPの調査実行、runner起動</td></tr><tr><td>OP</td><td>運用画面</td><td>alert/case受信、分類、Investigation作成、Google Chat通知</td><td>POSLA DB write、deploy、rollback</td></tr><tr><td>runner</td><td>調査実行</td><td>Git clone/fetch、コード検索、DB SELECT、ログ参照、Codex CLIレポート</td><td>git push、DB write、deploy、migration</td></tr><tr><td>人間</td><td>当面は小田さん</td><td>修正判断、コード修正、push、cell deploy、rollback承認</td><td>未確認のまま全cell一括反映</td></tr></tbody></table><h2 id="_14-3-接続一覧" tabindex="-1">14.3 接続一覧 <a class="header-anchor" href="#_14-3-接続一覧" aria-label="Permalink to &quot;14.3 接続一覧&quot;">​</a></h2><table tabindex="0"><thead><tr><th>向き</th><th>接続</th><th>用途</th><th>認証</th></tr></thead><tbody><tr><td>POSLA -&gt; OP</td><td><code>POST /api/alerts.php</code></td><td>監視アラート送信</td><td><code>X-OPS-ALERT-TOKEN</code></td></tr><tr><td>POSLA -&gt; OP</td><td><code>POST /api/cases.php</code></td><td>障害報告窓口からの報告送信</td><td><code>X-OPS-CASE-TOKEN</code></td></tr><tr><td>OP -&gt; POSLA</td><td><code>/api/monitor/ping.php</code></td><td>外形監視</td><td>なし</td></tr><tr><td>OP -&gt; POSLA</td><td><code>/api/monitor/cell-snapshot.php</code></td><td>cell registry / errors / monitor_events確認</td><td><code>X-POSLA-OPS-SECRET</code></td></tr><tr><td>OP -&gt; POSLA DB</td><td>MySQL SELECT</td><td>error_log / monitor_events / migration / deploy履歴確認</td><td>read-only DB user</td></tr><tr><td>OP -&gt; runner</td><td><code>/api/health.php</code> / <code>/api/investigate.php</code> / <code>/api/ai-report.php</code></td><td>調査実行</td><td><code>X-Runner-Token</code></td></tr><tr><td>runner -&gt; GitHub</td><td>clone / fetch / checkout</td><td>対象commitのコード確認</td><td>read-only deploy key / HTTPS token</td></tr><tr><td>runner -&gt; POSLA DB</td><td>MySQL SELECT</td><td>証跡確認</td><td>read-only DB user</td></tr></tbody></table><h2 id="_14-4-posla側で設定する値" tabindex="-1">14.4 POSLA側で設定する値 <a class="header-anchor" href="#_14-4-posla側で設定する値" aria-label="Permalink to &quot;14.4 POSLA側で設定する値&quot;">​</a></h2><p>POSLA control / cell の <code>app.env</code> または POSLA管理画面の API設定で、次を設定します。</p><table tabindex="0"><thead><tr><th>変数 / setting</th><th>用途</th></tr></thead><tbody><tr><td><code>POSLA_OP_CASE_ENDPOINT</code></td><td><code>https://&lt;op-domain&gt;/api/cases.php</code></td></tr><tr><td><code>POSLA_OP_CASE_TOKEN</code></td><td>OP側 <code>OPS_CASE_INGEST_TOKEN</code> と同じ値</td></tr><tr><td><code>POSLA_OP_ALERT_ENDPOINT</code></td><td><code>https://&lt;op-domain&gt;/api/alerts.php</code></td></tr><tr><td><code>POSLA_OP_ALERT_TOKEN</code></td><td>OP側 <code>OPS_ALERT_INGEST_TOKEN</code> と同じ値</td></tr><tr><td><code>POSLA_OPS_READ_SECRET</code></td><td>OPが <code>cell-snapshot.php</code> を読むための共有秘密</td></tr><tr><td><code>google_chat_webhook_url</code></td><td>OP側env未設定時のGoogle Chat通知先fallback</td></tr><tr><td><code>monitor_cron_secret</code></td><td>HTTP経由で <code>monitor-health.php</code> を実行する場合の共有秘密</td></tr></tbody></table><p>env と POSLA管理画面の両方に値がある場合は、env を優先します。</p><h2 id="_14-5-alert-の流れ" tabindex="-1">14.5 alert の流れ <a class="header-anchor" href="#_14-5-alert-の流れ" aria-label="Permalink to &quot;14.5 alert の流れ&quot;">​</a></h2><p>POSLAの <code>monitor-health.php</code> は、次のような異常を検知すると <code>monitor_events</code> に記録します。</p><ul><li>PHP error_log の閾値超過</li><li>Stripe Webhook失敗</li><li>5xx増加</li><li>認証エラー大量発生</li><li>予約通知失敗</li><li>cron heartbeat遅延</li></ul><p>OP連携が設定済みの場合、同じ内容をOPへ <code>alert ingest</code> します。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>monitor-health.php</span></span>
<span class="line"><span>  -&gt; monitor_events INSERT</span></span>
<span class="line"><span>  -&gt; OP /api/alerts.php POST</span></span>
<span class="line"><span>  -&gt; OPが分類</span></span>
<span class="line"><span>  -&gt; 要対応/緊急ならrunner調査</span></span>
<span class="line"><span>  -&gt; Google Chatへ短文通知</span></span></code></pre></div><h3 id="google-chatに飛ぶもの" tabindex="-1">Google Chatに飛ぶもの <a class="header-anchor" href="#google-chatに飛ぶもの" aria-label="Permalink to &quot;Google Chatに飛ぶもの&quot;">​</a></h3><table tabindex="0"><thead><tr><th>起点</th><th>Chat通知</th></tr></thead><tbody><tr><td>POSLAから直接届いた <code>要対応</code> / <code>緊急</code> alert</td><td>送る</td></tr><tr><td>POSLAから直接届いた <code>問題なし</code> / <code>要観察</code> alert</td><td>送らない</td></tr><tr><td>OP画面の <code>POSLA alerts同期</code></td><td>送らない</td></tr><tr><td>tenant画面の障害報告窓口</td><td>送る</td></tr></tbody></table><p><code>POSLA alerts同期</code> は過去分・滞留分の確認用途です。これをChat通知すると古いイベントまで一括通知されるため、通知対象外にしています。</p><h2 id="_14-6-障害報告の流れ" tabindex="-1">14.6 障害報告の流れ <a class="header-anchor" href="#_14-6-障害報告の流れ" aria-label="Permalink to &quot;14.6 障害報告の流れ&quot;">​</a></h2><p>tenant画面の障害報告窓口から報告されると、OPの <code>cases.php</code> が受け取ります。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>顧客 / 店舗スタッフ</span></span>
<span class="line"><span>  -&gt; 障害報告窓口</span></span>
<span class="line"><span>  -&gt; OP /api/cases.php</span></span>
<span class="line"><span>  -&gt; Investigation作成</span></span>
<span class="line"><span>  -&gt; runner調査</span></span>
<span class="line"><span>  -&gt; Codex CLIレポート</span></span>
<span class="line"><span>  -&gt; Google Chat</span></span></code></pre></div><p>Google Chatには、長い証跡ではなく次の2つを短く出します。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>【小田さんが今やること】</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【理由】</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>詳細な code hits、DB確認結果、monitor_events、AIレポート全文はOPのInvestigationに保存します。</p><h2 id="_14-7-monitor-event-の扱い" tabindex="-1">14.7 monitor_event の扱い <a class="header-anchor" href="#_14-7-monitor-event-の扱い" aria-label="Permalink to &quot;14.7 monitor_event の扱い&quot;">​</a></h2><p><code>monitor_events</code> は、POSLAが「監視上の異常」としてDBに残すイベントです。生ログではありません。</p><p>対応済みにする条件:</p><ul><li>テスト由来だと確認した</li><li>設定修正やコード修正が終わった</li><li>OP / runner の調査で「問題なし」と判断した</li><li>同じエラーが再発していない</li></ul><p>対応済みAPI:</p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">PATCH</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /api/posla/monitor-events.php</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Content-Type</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> application/json</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;event-id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;resolved&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>解決済みにしてよい例:</p><table tabindex="0"><thead><tr><th>event</th><th>判断</th></tr></thead><tbody><tr><td>テスト通知で作った <code>E1025</code></td><td>テスト完了後に解決済み</td></tr><tr><td>AI設定未投入の状態でAI機能をテストした <code>E9004</code></td><td>POSLA運営側の設定投入が完了していることを確認できたら解決済み</td></tr><tr><td>Stripe sandbox設定ミスのWebhook失敗</td><td>設定修正後に解決済み</td></tr></tbody></table><p>解決済みにしてはいけない例:</p><table tabindex="0"><thead><tr><th>event</th><th>理由</th></tr></thead><tbody><tr><td>決済できない状態が継続</td><td>Tier 0障害</td></tr><tr><td>DB接続失敗</td><td>POSLA全体停止の可能性</td></tr><tr><td>同一errorNoが増え続けている</td><td>原因未解消</td></tr></tbody></table><h2 id="_14-8-runner-が読むコード" tabindex="-1">14.8 runner が読むコード <a class="header-anchor" href="#_14-8-runner-が読むコード" aria-label="Permalink to &quot;14.8 runner が読むコード&quot;">​</a></h2><p>本番では runner は本番cellへSSHしてファイルを読むのではなく、GitHubのPOSLA repoを読みます。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GitHub main / release tag</span></span>
<span class="line"><span>  -&gt; runner workspace</span></span>
<span class="line"><span>  -&gt; 対象commitをcheckout</span></span>
<span class="line"><span>  -&gt; errorNo / API / 画面名で検索</span></span></code></pre></div><p>deploy済みcommitは、cell deploy時の <code>POSLA_DEPLOY_VERSION</code> と deploy manifest で追跡します。</p><p>人間のローカル修正運用:</p><ol><li>ローカルのPOSLAコードを修正</li><li>test / smoke</li><li>GitHubへpush</li><li>対象cellへdeploy</li><li>deploy manifestへcommitを記録</li><li>OP / runnerが同じcommitを読めるようになる</li></ol><p>runner workspaceの変更は正本ではありません。将来patch-runnerを使う場合も、直接mainへpushせずPR経由にします。</p><h2 id="_14-9-デプロイ日のe2e確認" tabindex="-1">14.9 デプロイ日のE2E確認 <a class="header-anchor" href="#_14-9-デプロイ日のe2e確認" aria-label="Permalink to &quot;14.9 デプロイ日のE2E確認&quot;">​</a></h2><p>本番接続後、必ず次を1回通します。</p><h3 id="alert-e2e" tabindex="-1">alert E2E <a class="header-anchor" href="#alert-e2e" aria-label="Permalink to &quot;alert E2E&quot;">​</a></h3><ol><li>POSLA管理画面から監視テスト通知を実行</li><li><code>monitor_events</code> に記録される</li><li>OPの Alert に入る</li><li>要対応 / 緊急なら Investigation が作成される</li><li>runner が調査する</li><li>Codex CLI レポートが作成される</li><li>Google Chat に短文通知が届く</li><li>OPで詳細を確認する</li><li>テストeventを <code>resolved=1</code> にする</li></ol><h3 id="障害報告-e2e" tabindex="-1">障害報告 E2E <a class="header-anchor" href="#障害報告-e2e" aria-label="Permalink to &quot;障害報告 E2E&quot;">​</a></h3><ol><li>tenant画面の障害報告窓口からテスト報告</li><li>OPの Cases に入る</li><li>Investigation が作成される</li><li>runner / Codex調査が走る</li><li>Google Chatに <code>小田さんが今やること</code> が届く</li><li>テストcaseをOPで削除または対応済みにする</li></ol><h2 id="_14-10-日常運用" tabindex="-1">14.10 日常運用 <a class="header-anchor" href="#_14-10-日常運用" aria-label="Permalink to &quot;14.10 日常運用&quot;">​</a></h2><p>毎日見るもの:</p><table tabindex="0"><thead><tr><th>場所</th><th>確認内容</th></tr></thead><tbody><tr><td>OP 総合状態</td><td>POSLA ping、DB read-only、runner health</td></tr><tr><td>OP 顧客cell</td><td>新規cellが自動同期されているか</td></tr><tr><td>OP Alert</td><td><code>要対応</code> / <code>緊急</code> がないか</td></tr><tr><td>OP Cases</td><td>顧客障害報告が残っていないか</td></tr><tr><td>OP Investigations</td><td>人間確認待ちがないか</td></tr><tr><td>Google Chat</td><td>新規alert / case通知</td></tr></tbody></table><p>対応の基本:</p><ol><li>Google Chatを見る</li><li><code>小田さんが今やること</code> を読む</li><li>顧客確認、設定修正、コード修正、様子見のどれかを判断</li><li>コード修正が必要ならPOSLA repoで修正</li><li>対象cellだけdeploy</li><li>smoke</li><li>OP / POSLA側のeventを解決済みにする</li></ol><h2 id="_14-11-phase-1-で禁止すること" tabindex="-1">14.11 Phase 1 で禁止すること <a class="header-anchor" href="#_14-11-phase-1-で禁止すること" aria-label="Permalink to &quot;14.11 Phase 1 で禁止すること&quot;">​</a></h2><ul><li>OPから直接DB UPDATE / DELETE / INSERT</li><li>runnerからDB write</li><li>runnerからgit push</li><li>runnerから本番deploy</li><li>runnerからmigration</li><li>runnerからrollback</li><li>secret / env実値をAIに渡す</li><li>顧客の個人情報や決済情報をAIへ渡す</li></ul><h2 id="_14-12-本番接続で詰まった時" tabindex="-1">14.12 本番接続で詰まった時 <a class="header-anchor" href="#_14-12-本番接続で詰まった時" aria-label="Permalink to &quot;14.12 本番接続で詰まった時&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>確認</th></tr></thead><tbody><tr><td>OPにcellが出ない</td><td>POSLA <code>cell-snapshot.php</code>、<code>POSLA_OPS_READ_SECRET</code>、Cell Registry</td></tr><tr><td>OPにalertが来ない</td><td><code>POSLA_OP_ALERT_ENDPOINT</code>、<code>POSLA_OP_ALERT_TOKEN</code>、OP <code>OPS_ALERT_INGEST_TOKEN</code></td></tr><tr><td>障害報告が来ない</td><td><code>POSLA_OP_CASE_ENDPOINT</code>、<code>POSLA_OP_CASE_TOKEN</code>、OP <code>OPS_CASE_INGEST_TOKEN</code></td></tr><tr><td>Chatに届かない</td><td>OP <code>OPS_GOOGLE_CHAT_WEBHOOK_URL</code>、POSLA <code>google_chat_webhook_url</code> fallback</td></tr><tr><td>runner調査が走らない</td><td><code>OPS_RUNNER_BASE_URL</code>、<code>OPS_RUNNER_TOKEN</code>、runner <code>RUNNER_AUTH_TOKEN</code></td></tr><tr><td>AIレポートが作られない</td><td>runner <code>RUNNER_CODEX_EXECUTE</code>、Codex実行ゲート、Codex login状態</td></tr><tr><td>logs skipped</td><td>runner <code>RUNNER_LOG_FILES</code> が未設定</td></tr><tr><td>DB read-only失敗</td><td><code>posla_ops_ro</code>、接続元Host、Firewall、DB名</td></tr></tbody></table><h2 id="_14-13-関連ドキュメント" tabindex="-1">14.13 関連ドキュメント <a class="header-anchor" href="#_14-13-関連ドキュメント" aria-label="Permalink to &quot;14.13 関連ドキュメント&quot;">​</a></h2><ul><li><a href="./07-monitor.html">7. 監視・アラート</a></li><li><a href="./11-cell-deployment.html">11. Cell配備運用</a></li><li><a href="./12-production-deploy-runbook.html">12. 本番デプロイ手順書</a></li><li><a href="./production-api-checklist.html">13. 本番切替 API チェックリスト</a></li></ul>`,61)])])}const u=e(d,[["render",l]]);export{P as __pageData,u as default};
